CREATE OR REPLACE FUNCTION ledger.get_account(p_id integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_account record;
  v_balance numeric;
  v_body text;
  v_rows text[];
  v_cumul numeric := 0;
  v_sign integer;
  r record;
BEGIN
  SELECT * INTO v_account FROM ledger.account WHERE id = p_id;
  IF NOT FOUND THEN RETURN pgv.empty('Compte introuvable'); END IF;

  v_balance := ledger._account_balance(p_id);
  v_sign := ledger._type_sign(v_account.type);

  v_body := pgv.breadcrumb(VARIADIC ARRAY[
    'Plan comptable', pgv.call_ref('get_accounts'),
    v_account.code || ' — ' || v_account.label
  ]);

  v_body := v_body || pgv.dl(VARIADIC ARRAY[
    'Code', v_account.code,
    'Libellé', pgv.esc(v_account.label),
    'Type', pgv.badge(ledger._type_label(v_account.type),
      CASE v_account.type WHEN 'asset' THEN 'info' WHEN 'liability' THEN 'warning'
        WHEN 'equity' THEN 'default' WHEN 'revenue' THEN 'success' WHEN 'expense' THEN 'danger' END),
    'Solde', to_char(v_balance, 'FM999 990.00') || ' €'
  ]);

  -- Lignes du grand livre
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT je.entry_date, je.reference, je.id AS entry_id,
           el.debit, el.credit, el.label
      FROM ledger.entry_line el
      JOIN ledger.journal_entry je ON je.id = el.journal_entry_id
     WHERE el.account_id = p_id AND je.posted = true
     ORDER BY je.entry_date, je.id
  LOOP
    v_cumul := v_cumul + (r.debit - r.credit) * v_sign;
    v_rows := v_rows || ARRAY[
      to_char(r.entry_date, 'DD/MM/YYYY'),
      format('<a href="%s">%s</a>', pgv.call_ref('get_entry', jsonb_build_object('p_id', r.entry_id)), pgv.esc(r.reference)),
      pgv.esc(r.label),
      CASE WHEN r.debit > 0 THEN to_char(r.debit, 'FM999 990.00') ELSE '' END,
      CASE WHEN r.credit > 0 THEN to_char(r.credit, 'FM999 990.00') ELSE '' END,
      to_char(v_cumul, 'FM999 990.00')
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := v_body || pgv.empty('Aucun mouvement', 'Ce compte n''a pas encore de lignes validées.');
  ELSE
    v_body := v_body || pgv.md_table(
      ARRAY['Date', 'Référence', 'Libellé', 'Débit', 'Crédit', 'Solde'],
      v_rows
    );
  END IF;

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION ledger.get_account(integer) IS 'Grand livre d''un compte : fiche + lignes d''écritures avec solde cumulé';

CREATE OR REPLACE FUNCTION ledger.get_accounts()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_rows text[];
  v_body text;
  r record;
BEGIN
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT a.id, a.code, a.label, a.type,
           ledger._account_balance(a.id) AS balance
      FROM ledger.account a
     WHERE a.active
     ORDER BY a.code
  LOOP
    v_rows := v_rows || ARRAY[
      format('<a href="%s">%s</a>', pgv.call_ref('get_account', jsonb_build_object('p_id', r.id)), pgv.esc(r.code)),
      pgv.esc(r.label),
      pgv.badge(ledger._type_label(r.type),
        CASE r.type WHEN 'asset' THEN 'info' WHEN 'liability' THEN 'warning'
          WHEN 'equity' THEN 'default' WHEN 'revenue' THEN 'success' WHEN 'expense' THEN 'danger' END),
      to_char(r.balance, 'FM999 990.00') || ' €'
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := pgv.empty('Aucun compte', 'Le plan comptable est vide.');
  ELSE
    v_body := pgv.md_table(
      ARRAY['Code', 'Libellé', 'Type', 'Solde'],
      v_rows, 20
    );
  END IF;

  RETURN pgv.breadcrumb(VARIADIC ARRAY['Plan comptable']) || v_body;
END;
$function$;
COMMENT ON FUNCTION ledger.get_accounts() IS 'Plan comptable : table paginée des comptes avec soldes';

CREATE OR REPLACE FUNCTION ledger.get_bilan(p_year integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_year integer;
  v_start date;
  v_end date;
  v_body text;
  v_rows_r text[];
  v_rows_e text[];
  v_total_revenue numeric := 0;
  v_total_expense numeric := 0;
  v_resultat numeric;
  r record;
BEGIN
  v_year := coalesce(p_year, extract(year FROM CURRENT_DATE)::integer);
  v_start := make_date(v_year, 1, 1);
  v_end := make_date(v_year, 12, 31);

  v_body := pgv.breadcrumb(VARIADIC ARRAY['Bilan']);

  -- Sélecteur année
  v_body := v_body || '<div class="grid">'
    || format('<a href="%s" role="button" class="outline">%s</a>', pgv.call_ref('get_bilan', jsonb_build_object('p_year', v_year - 1)), (v_year - 1)::text)
    || format('<a href="%s" role="button">%s</a>', pgv.call_ref('get_bilan', jsonb_build_object('p_year', v_year)), v_year::text)
    || format('<a href="%s" role="button" class="outline">%s</a>', pgv.call_ref('get_bilan', jsonb_build_object('p_year', v_year + 1)), (v_year + 1)::text)
    || '</div>';

  -- Produits (revenue = classe 7)
  v_rows_r := ARRAY[]::text[];
  FOR r IN
    SELECT a.code, a.label,
           coalesce(sum(el.credit) - sum(el.debit), 0) AS balance
      FROM ledger.account a
      LEFT JOIN ledger.entry_line el ON el.account_id = a.id
        AND EXISTS (SELECT 1 FROM ledger.journal_entry je
                     WHERE je.id = el.journal_entry_id AND je.posted = true
                       AND je.entry_date >= v_start AND je.entry_date <= v_end)
     WHERE a.type = 'revenue' AND a.active
     GROUP BY a.id, a.code, a.label
     ORDER BY a.code
  LOOP
    v_total_revenue := v_total_revenue + r.balance;
    IF r.balance <> 0 THEN
      v_rows_r := v_rows_r || ARRAY[
        pgv.esc(r.code), pgv.esc(r.label),
        to_char(r.balance, 'FM999 990.00') || ' €'
      ];
    END IF;
  END LOOP;

  -- Charges (expense = classe 6)
  v_rows_e := ARRAY[]::text[];
  FOR r IN
    SELECT a.code, a.label,
           coalesce(sum(el.debit) - sum(el.credit), 0) AS balance
      FROM ledger.account a
      LEFT JOIN ledger.entry_line el ON el.account_id = a.id
        AND EXISTS (SELECT 1 FROM ledger.journal_entry je
                     WHERE je.id = el.journal_entry_id AND je.posted = true
                       AND je.entry_date >= v_start AND je.entry_date <= v_end)
     WHERE a.type = 'expense' AND a.active
     GROUP BY a.id, a.code, a.label
     ORDER BY a.code
  LOOP
    v_total_expense := v_total_expense + r.balance;
    IF r.balance <> 0 THEN
      v_rows_e := v_rows_e || ARRAY[
        pgv.esc(r.code), pgv.esc(r.label),
        to_char(r.balance, 'FM999 990.00') || ' €'
      ];
    END IF;
  END LOOP;

  v_resultat := v_total_revenue - v_total_expense;

  -- Stats résumé
  v_body := v_body || pgv.grid(VARIADIC ARRAY[
    pgv.stat('Produits', to_char(v_total_revenue, 'FM999 990.00') || ' €'),
    pgv.stat('Charges', to_char(v_total_expense, 'FM999 990.00') || ' €'),
    pgv.stat('Résultat net', to_char(v_resultat, 'FM999 990.00') || ' €',
      CASE WHEN v_resultat >= 0 THEN 'Bénéfice' ELSE 'Déficit' END)
  ]);

  -- Tables détail
  v_body := v_body || pgv.tabs(VARIADIC ARRAY[
    'Produits (classe 7)',
    CASE WHEN array_length(v_rows_r, 1) IS NULL
      THEN pgv.empty('Aucun produit sur ' || v_year)
      ELSE pgv.md_table(ARRAY['Code', 'Libellé', 'Montant'], v_rows_r)
        || '<p><strong>Total produits : ' || to_char(v_total_revenue, 'FM999 990.00') || ' €</strong></p>'
    END,
    'Charges (classe 6)',
    CASE WHEN array_length(v_rows_e, 1) IS NULL
      THEN pgv.empty('Aucune charge sur ' || v_year)
      ELSE pgv.md_table(ARRAY['Code', 'Libellé', 'Montant'], v_rows_e)
        || '<p><strong>Total charges : ' || to_char(v_total_expense, 'FM999 990.00') || ' €</strong></p>'
    END
  ]);

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION ledger.get_bilan(integer) IS 'Bilan P&L : produits vs charges par compte, résultat net. Filtre par année.';

CREATE OR REPLACE FUNCTION ledger.get_entries()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_rows text[];
  v_body text;
  r record;
BEGIN
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT je.id, je.entry_date, je.reference, je.description, je.posted,
           coalesce(sum(el.debit), 0) AS total_debit
      FROM ledger.journal_entry je
      LEFT JOIN ledger.entry_line el ON el.journal_entry_id = je.id
     GROUP BY je.id
     ORDER BY je.entry_date DESC, je.id DESC
  LOOP
    v_rows := v_rows || ARRAY[
      to_char(r.entry_date, 'DD/MM/YYYY'),
      format('<a href="%s">%s</a>', pgv.call_ref('get_entry', jsonb_build_object('p_id', r.id)), pgv.esc(r.reference)),
      pgv.esc(r.description),
      to_char(r.total_debit, 'FM999 990.00') || ' €',
      CASE WHEN r.posted THEN pgv.badge('Validée', 'success') ELSE pgv.badge('Brouillon', 'warning') END
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := pgv.empty('Aucune écriture', 'Créez votre première écriture comptable.');
  ELSE
    v_body := pgv.md_table(
      ARRAY['Date', 'Référence', 'Description', 'Montant', 'Statut'],
      v_rows, 15
    );
  END IF;

  v_body := v_body || format('<p><a href="%s" role="button">Nouvelle écriture</a></p>', pgv.call_ref('get_entry_form'));

  RETURN pgv.breadcrumb(VARIADIC ARRAY['Écritures']) || v_body;
END;
$function$;
COMMENT ON FUNCTION ledger.get_entries() IS 'Journal des écritures : table paginée avec statut';

CREATE OR REPLACE FUNCTION ledger.get_entry(p_id integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_entry record;
  v_body text;
  v_rows text[];
  v_total_debit numeric := 0;
  v_total_credit numeric := 0;
  v_balanced boolean;
  v_accounts_options text;
  r record;
BEGIN
  SELECT * INTO v_entry FROM ledger.journal_entry WHERE id = p_id;
  IF NOT FOUND THEN RETURN pgv.empty('Écriture introuvable'); END IF;

  v_body := pgv.breadcrumb(VARIADIC ARRAY[
    'Écritures', pgv.call_ref('get_entries'),
    v_entry.reference
  ]);

  v_body := v_body || pgv.dl(VARIADIC ARRAY[
    'Date', to_char(v_entry.entry_date, 'DD/MM/YYYY'),
    'Référence', pgv.esc(v_entry.reference),
    'Description', pgv.esc(v_entry.description),
    'Statut', CASE WHEN v_entry.posted THEN pgv.badge('Validée', 'success') ELSE pgv.badge('Brouillon', 'warning') END
  ]);

  -- Lignes
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT el.id, el.account_id, a.code, a.label AS account_label,
           el.debit, el.credit, el.label
      FROM ledger.entry_line el
      JOIN ledger.account a ON a.id = el.account_id
     WHERE el.journal_entry_id = p_id
     ORDER BY el.id
  LOOP
    v_total_debit := v_total_debit + r.debit;
    v_total_credit := v_total_credit + r.credit;
    v_rows := v_rows || ARRAY[
      format('<a href="%s">%s</a> %s', pgv.call_ref('get_account', jsonb_build_object('p_id', r.account_id)), pgv.esc(r.code), pgv.esc(r.account_label)),
      pgv.esc(r.label),
      CASE WHEN r.debit > 0 THEN to_char(r.debit, 'FM999 990.00') ELSE '' END,
      CASE WHEN r.credit > 0 THEN to_char(r.credit, 'FM999 990.00') ELSE '' END,
      CASE WHEN NOT v_entry.posted
        THEN pgv.action('post_line_delete', 'Suppr.', jsonb_build_object('id', r.id, 'entry_id', p_id), 'Supprimer cette ligne ?', 'danger')
        ELSE ''
      END
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := v_body || pgv.empty('Aucune ligne', 'Ajoutez des lignes à cette écriture.');
  ELSE
    -- Add totals row
    v_rows := v_rows || ARRAY[
      '<strong>Total</strong>', '',
      '<strong>' || to_char(v_total_debit, 'FM999 990.00') || '</strong>',
      '<strong>' || to_char(v_total_credit, 'FM999 990.00') || '</strong>',
      ''
    ];
    v_body := v_body || pgv.md_table(
      ARRAY['Compte', 'Libellé', 'Débit', 'Crédit', ''],
      v_rows
    );
  END IF;

  -- Alert si déséquilibrée
  v_balanced := ledger._entry_balanced(p_id);
  IF NOT v_balanced AND v_total_debit + v_total_credit > 0 THEN
    v_body := v_body || pgv.alert(
      'Écriture déséquilibrée : débit ' || to_char(v_total_debit, 'FM999 990.00')
        || ' € ≠ crédit ' || to_char(v_total_credit, 'FM999 990.00') || ' €',
      'danger'
    );
  END IF;

  -- Formulaire ajout ligne (brouillon uniquement)
  IF NOT v_entry.posted THEN
    -- Build account options
    v_accounts_options := '';
    FOR r IN SELECT id, code, label FROM ledger.account WHERE active ORDER BY code LOOP
      v_accounts_options := v_accounts_options
        || '<option value="' || r.id || '">' || pgv.esc(r.code) || ' — ' || pgv.esc(r.label) || '</option>';
    END LOOP;

    v_body := v_body || '<details><summary>Ajouter une ligne</summary>'
      || '<form data-rpc="post_line_add">'
      || '<input type="hidden" name="entry_id" value="' || p_id || '">'
      || '<label>Compte <select name="account_id" required>'
      || '<option value="">— Choisir —</option>'
      || v_accounts_options
      || '</select></label>'
      || '<div class="grid">'
      || '<label>Débit <input type="number" name="debit" value="0" step="0.01" min="0"></label>'
      || '<label>Crédit <input type="number" name="credit" value="0" step="0.01" min="0"></label>'
      || '</div>'
      || '<label>Libellé <input type="text" name="label" value=""></label>'
      || '<button type="submit">Ajouter</button>'
      || '</form></details>';

    -- Actions brouillon
    v_body := v_body || '<div class="grid">'
      || format('<a href="%s" role="button" class="outline">Modifier</a>', pgv.call_ref('get_entry_form', jsonb_build_object('p_id', p_id)))
      || pgv.action('post_entry_post', 'Valider', jsonb_build_object('id', p_id), 'Valider cette écriture ? Elle deviendra immutable.')
      || pgv.action('post_entry_delete', 'Supprimer', jsonb_build_object('id', p_id), 'Supprimer ce brouillon ?', 'danger')
      || '</div>';
  END IF;

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION ledger.get_entry(integer) IS 'Fiche écriture : détail + lignes + formulaire ajout ligne si brouillon';

CREATE OR REPLACE FUNCTION ledger.get_entry_form(p_id integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_entry record;
  v_body text;
  v_title text;
BEGIN
  IF p_id IS NOT NULL THEN
    SELECT * INTO v_entry FROM ledger.journal_entry WHERE id = p_id;
    IF NOT FOUND THEN RETURN pgv.empty('Écriture introuvable'); END IF;
    IF v_entry.posted THEN RETURN pgv.alert('Écriture validée : modification impossible.', 'danger'); END IF;
    v_title := 'Modifier ' || v_entry.reference;
  ELSE
    v_title := 'Nouvelle écriture';
  END IF;

  v_body := pgv.breadcrumb(VARIADIC ARRAY[
    'Écritures', pgv.call_ref('get_entries'),
    v_title
  ]);

  v_body := v_body || '<form data-rpc="post_entry_save">';

  IF p_id IS NOT NULL THEN
    v_body := v_body || '<input type="hidden" name="id" value="' || p_id || '">';
  END IF;

  v_body := v_body
    || '<label>Date <input type="date" name="entry_date" value="'
      || CASE WHEN p_id IS NOT NULL THEN to_char(v_entry.entry_date, 'YYYY-MM-DD') ELSE to_char(CURRENT_DATE, 'YYYY-MM-DD') END
      || '" required></label>'
    || '<label>Référence <input type="text" name="reference" value="'
      || CASE WHEN p_id IS NOT NULL THEN pgv.esc(v_entry.reference) ELSE '' END
      || '" required placeholder="EX: ACH-001"></label>'
    || '<label>Description <input type="text" name="description" value="'
      || CASE WHEN p_id IS NOT NULL THEN pgv.esc(v_entry.description) ELSE '' END
      || '" required placeholder="Achat matériaux chantier X"></label>'
    || '<button type="submit">Enregistrer</button>'
    || '</form>';

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION ledger.get_entry_form(integer) IS 'Formulaire création/édition écriture comptable';

CREATE OR REPLACE FUNCTION ledger.get_index()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_body text;
  v_solde_banque numeric;
  v_ca_mois numeric;
  v_charges_mois numeric;
  v_resultat numeric;
  v_month_start date;
  v_month_end date;
  v_rows text[];
  r record;
BEGIN
  v_month_start := date_trunc('month', CURRENT_DATE)::date;
  v_month_end := (date_trunc('month', CURRENT_DATE) + interval '1 month' - interval '1 day')::date;

  -- KPIs
  SELECT ledger._account_balance(a.id) INTO v_solde_banque
    FROM ledger.account a WHERE a.code = '512';

  v_ca_mois := ledger._period_total('revenue', v_month_start, v_month_end);
  v_charges_mois := ledger._period_total('expense', v_month_start, v_month_end);
  v_resultat := coalesce(v_ca_mois, 0) - coalesce(v_charges_mois, 0);

  v_body := pgv.grid(VARIADIC ARRAY[
    pgv.stat('Solde banque', to_char(coalesce(v_solde_banque, 0), 'FM999 990.00') || ' €'),
    pgv.stat('CA du mois', to_char(coalesce(v_ca_mois, 0), 'FM999 990.00') || ' €'),
    pgv.stat('Charges du mois', to_char(coalesce(v_charges_mois, 0), 'FM999 990.00') || ' €'),
    pgv.stat('Résultat', to_char(v_resultat, 'FM999 990.00') || ' €')
  ]);

  -- Écritures récentes
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT je.id, je.entry_date, je.reference, je.description, je.posted,
           coalesce(sum(el.debit), 0) AS total_debit
      FROM ledger.journal_entry je
      LEFT JOIN ledger.entry_line el ON el.journal_entry_id = je.id
     GROUP BY je.id
     ORDER BY je.entry_date DESC, je.id DESC
     LIMIT 10
  LOOP
    v_rows := v_rows || ARRAY[
      to_char(r.entry_date, 'DD/MM/YYYY'),
      format('<a href="%s">%s</a>', pgv.call_ref('get_entry', jsonb_build_object('p_id', r.id)), pgv.esc(r.reference)),
      pgv.esc(r.description),
      to_char(r.total_debit, 'FM999 990.00') || ' €',
      CASE WHEN r.posted THEN pgv.badge('Validée', 'success') ELSE pgv.badge('Brouillon', 'warning') END
    ];
  END LOOP;

  v_body := v_body || pgv.tabs(VARIADIC ARRAY[
    'Écritures récentes',
    CASE WHEN array_length(v_rows, 1) IS NULL
      THEN pgv.empty('Aucune écriture', 'Créez votre première écriture.')
      ELSE pgv.md_table(ARRAY['Date', 'Référence', 'Description', 'Montant', 'Statut'], v_rows)
    END
  ]);

  v_body := v_body || format('<p><a href="%s" role="button">Nouvelle écriture</a></p>', pgv.call_ref('get_entry_form'));

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION ledger.get_index() IS 'Dashboard comptabilité : KPIs (banque, CA, charges, résultat) + écritures récentes';

CREATE OR REPLACE FUNCTION ledger.get_tva(p_year integer DEFAULT NULL::integer, p_quarter integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_year integer;
  v_quarter integer;
  v_start date;
  v_end date;
  v_collectee numeric;
  v_deductible numeric;
  v_solde numeric;
  v_body text;
  v_rows text[];
  r record;
BEGIN
  v_year := coalesce(p_year, extract(year FROM CURRENT_DATE)::integer);
  v_quarter := coalesce(p_quarter, extract(quarter FROM CURRENT_DATE)::integer);

  v_start := make_date(v_year, (v_quarter - 1) * 3 + 1, 1);
  v_end := (v_start + interval '3 months' - interval '1 day')::date;

  v_body := pgv.breadcrumb(VARIADIC ARRAY['TVA']);

  -- Sélecteur période
  v_body := v_body || '<div class="grid">'
    || format('<a href="%s" role="button" class="outline">T1</a>', pgv.call_ref('get_tva', jsonb_build_object('p_year', v_year, 'p_quarter', 1)))
    || format('<a href="%s" role="button" class="outline">T2</a>', pgv.call_ref('get_tva', jsonb_build_object('p_year', v_year, 'p_quarter', 2)))
    || format('<a href="%s" role="button" class="outline">T3</a>', pgv.call_ref('get_tva', jsonb_build_object('p_year', v_year, 'p_quarter', 3)))
    || format('<a href="%s" role="button" class="outline">T4</a>', pgv.call_ref('get_tva', jsonb_build_object('p_year', v_year, 'p_quarter', 4)))
    || '</div>';

  v_body := v_body || '<p>Période : T' || v_quarter || ' ' || v_year
    || ' (' || to_char(v_start, 'DD/MM/YYYY') || ' — ' || to_char(v_end, 'DD/MM/YYYY') || ')</p>';

  -- TVA collectée (4457) = SUM credit - SUM debit sur la période
  SELECT coalesce(sum(el.credit) - sum(el.debit), 0) INTO v_collectee
    FROM ledger.entry_line el
    JOIN ledger.journal_entry je ON je.id = el.journal_entry_id
    JOIN ledger.account a ON a.id = el.account_id
   WHERE a.code = '4457' AND je.posted = true
     AND je.entry_date >= v_start AND je.entry_date <= v_end;

  -- TVA déductible (4456) = SUM debit - SUM credit sur la période
  SELECT coalesce(sum(el.debit) - sum(el.credit), 0) INTO v_deductible
    FROM ledger.entry_line el
    JOIN ledger.journal_entry je ON je.id = el.journal_entry_id
    JOIN ledger.account a ON a.id = el.account_id
   WHERE a.code = '4456' AND je.posted = true
     AND je.entry_date >= v_start AND je.entry_date <= v_end;

  v_solde := v_collectee - v_deductible;

  v_body := v_body || pgv.grid(VARIADIC ARRAY[
    pgv.stat('TVA collectée', to_char(v_collectee, 'FM999 990.00') || ' €'),
    pgv.stat('TVA déductible', to_char(v_deductible, 'FM999 990.00') || ' €'),
    pgv.stat(
      CASE WHEN v_solde >= 0 THEN 'TVA à reverser' ELSE 'Crédit de TVA' END,
      to_char(abs(v_solde), 'FM999 990.00') || ' €'
    )
  ]);

  -- Détail par écriture
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT je.entry_date, je.reference, je.id AS entry_id,
           el.debit, el.credit, a.code, a.label AS account_label
      FROM ledger.entry_line el
      JOIN ledger.journal_entry je ON je.id = el.journal_entry_id
      JOIN ledger.account a ON a.id = el.account_id
     WHERE a.code IN ('4456', '4457') AND je.posted = true
       AND je.entry_date >= v_start AND je.entry_date <= v_end
     ORDER BY je.entry_date, je.id
  LOOP
    v_rows := v_rows || ARRAY[
      to_char(r.entry_date, 'DD/MM/YYYY'),
      format('<a href="%s">%s</a>', pgv.call_ref('get_entry', jsonb_build_object('p_id', r.entry_id)), pgv.esc(r.reference)),
      r.code || ' ' || pgv.esc(r.account_label),
      CASE WHEN r.debit > 0 THEN to_char(r.debit, 'FM999 990.00') ELSE '' END,
      CASE WHEN r.credit > 0 THEN to_char(r.credit, 'FM999 990.00') ELSE '' END
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NOT NULL THEN
    v_body := v_body || '<h4>Détail mouvements TVA</h4>'
      || pgv.md_table(ARRAY['Date', 'Référence', 'Compte', 'Débit', 'Crédit'], v_rows);
  ELSE
    v_body := v_body || pgv.empty('Aucun mouvement TVA sur la période');
  END IF;

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION ledger.get_tva(integer,integer) IS 'Déclaration TVA : collectée, déductible, solde. Filtre par trimestre/année.';

